document.addEventListener('DOMContentLoaded',function(){function initializePollCards(container){const cards=container.querySelectorAll('.poll-card');const radios=container.querySelectorAll('input[type="radio"]');const updateSelectedCard=()=>{radios.forEach(radio=>{const card=radio.closest('.poll-card');if(card){if(radio.checked){card.classList.add('selected')}else{card.classList.remove('selected')}}})};cards.forEach(card=>{card.addEventListener('click',()=>{const radio=card.querySelector('input[type="radio"]');if(radio&&!radio.checked){radio.checked=true;updateSelectedCard();const changeEvent=new Event('change',{bubbles:true});radio.dispatchEvent(changeEvent)}})});updateSelectedCard()}document.querySelectorAll('.poll-cards-container').forEach(initializePollCards);function initializeInputValidation(){const inputs=document.querySelectorAll('input[type="text"], input[type="number"], select');inputs.forEach(input=>{const wrapper=document.createElement('div');wrapper.style.position='relative';if(input.parentNode){input.parentNode.insertBefore(wrapper,input);wrapper.appendChild(input)}const validationIcon=document.createElement('span');validationIcon.className='validation-icon';wrapper.appendChild(validationIcon);input.addEventListener('input',function(){if(this.value.trim()!==''){this.classList.remove('input-invalid');this.classList.add('input-valid')}else{this.classList.remove('input-valid')}});input.addEventListener('blur',function(){if(this.required&&this.value.trim()===''){this.classList.add('input-invalid')}})})}function initializeRippleEffect(){const buttons=document.querySelectorAll('.btn');buttons.forEach(button=>{button.addEventListener('click',function(e){const ripple=document.createElement('span');ripple.className='ripple';const rect=this.getBoundingClientRect();const size=Math.max(rect.width,rect.height);ripple.style.width=ripple.style.height=size+'px';ripple.style.left=(e.clientX-rect.left-size/2)+'px';ripple.style.top=(e.clientY-rect.top-size/2)+'px';this.appendChild(ripple);setTimeout(()=>ripple.remove(),600)})})}initializeInputValidation();initializeRippleEffect()});
